const rows = $input.all();
if (rows.length === 0) {
  return [{ json: { text: "No history", last_date: new Date().toISOString().split('T')[0] } }];
}

// reverse to get chronological order
const data = rows.map(r => r.json).reverse();
const text = data.map(d => `${d.date}: ${d.close_price}`).join('\n');
const last_date = data[data.length - 1].date;

return [{ json: { text, last_date } }];

const raw = $input.first().json.content || $input.first().json.response || '';
let jsonStr = raw.trim();
const firstBrace = jsonStr.indexOf('{');
const lastBrace = jsonStr.lastIndexOf('}');
if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
  jsonStr = jsonStr.substring(firstBrace, lastBrace + 1);
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  // fallback default values if parsing fails
  parsed = {
    predicted_close_price: 0,
    trend: "FLAT",
    confidence: 0,
    reasoning: "Failed to parse model response: " + raw.substring(0, 100)
  };
}

// Compute prediction date (skipping weekends)
const lastDateStr = $('Format History for LLM').first().json.last_date;
const lastDate = new Date(lastDateStr);
const nextDay = new Date(lastDate);
nextDay.setDate(lastDate.getDate() + 1);
while (nextDay.getDay() === 0 || nextDay.getDay() === 6) {
  nextDay.setDate(nextDay.getDate() + 1);
}
const prediction_date = nextDay.toISOString().split('T')[0];

return [{
  json: {
    symbol: "^GSPC",
    prediction_date,
    predicted_close_price: parsed.predicted_close_price || 0,
    trend: parsed.trend || "FLAT",
    confidence: parsed.confidence || 0,
    reasoning: parsed.reasoning || "No reasoning provided.",
    model_name: $env.OLLAMA_CLOUD_MODEL || "gemma3:4b"
  }
}];
